/**
 * Mode: Run Once for All Items
 * Logic: Determine onboarding state safely.
 */
const inputData = items[0].json;

const context = inputData.context || inputData || {};

const user = context.user || null;
const exists = context.exists || false;
const lang = context.language || null; 

// Determinar el estado
let state;
if (user && user.onboarding_state) {
  state = user.onboarding_state; // PENDING_CONTACT, READY, etc.
} else if (!exists) {

  state = lang ? 'PENDING_LINK' : 'NO_LANGUAGE'; 
} else {
  state = 'UNKNOWN';
}

return [{
  json: {
    ...inputData,
    exists: exists,
    onboarding_state: state
  }
}];

